import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),i={name:"guide/getting-started.md"};function s(r,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><h2 id="about-central" tabindex="-1">About Central <a class="header-anchor" href="#about-central" aria-label="Permalink to &quot;About Central&quot;">​</a></h2><p>Central is a next-generation automation platform that pairs a low/no-code integration engine with a data quality management solution to synchronize data across multiple systems. It addresses complex data synchronization and workflow needs across eCommerce, ERP, CRM, HRIS, Purchasing, and Supply Chain systems — with minimal coding required.</p><p>Central covers the full software development lifecycle: design, build, test, version control, deployment, monitoring, and maintenance. It also emphasizes data quality, metadata management, relationship mapping, and data architecture governance.</p><h2 id="purpose-of-this-guide" tabindex="-1">Purpose of This Guide <a class="header-anchor" href="#purpose-of-this-guide" aria-label="Permalink to &quot;Purpose of This Guide&quot;">​</a></h2><p>This guide assists users and developers in building and customizing your company&#39;s integration platform. It assumes the reader has a technical understanding of database structure, data terminology, your business solutions, and data inputs and downstream consequences.</p><p>For questions or support, contact <a href="mailto:support@teamcentral.ai" target="_blank" rel="noreferrer">support@teamcentral.ai</a>.</p><h2 id="getting-started-checklist" tabindex="-1">Getting Started Checklist <a class="header-anchor" href="#getting-started-checklist" aria-label="Permalink to &quot;Getting Started Checklist&quot;">​</a></h2><p>Ensure you have the following before beginning to build your model:</p><ul><li>Central software URL</li><li>Central Admin access</li><li>Working knowledge of the software systems you plan to integrate</li><li>Technical documentation for each connecting software system, including the authentication information</li></ul><h2 id="key-definitions" tabindex="-1">Key Definitions <a class="header-anchor" href="#key-definitions" aria-label="Permalink to &quot;Key Definitions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong><a href="./reference-common-model.html">Common Model</a></strong></td><td>The starting point for defining common entities within your business (e.g. Customer, Vendor, Employee, Sales Order). All publishing and subscribing flows through the Common Model.</td></tr><tr><td><strong>Data Model</strong></td><td>Your customized copy of the Common Model, defining the data you need to flow between systems. It consists of common fields and unique, personalized Schema Definitions.</td></tr><tr><td><strong>Data Model Property</strong></td><td>The actual data points that flow between systems (e.g. a <em>Customer</em> Data Model may include <em>name</em>, <em>address</em>, and <em>email</em>).</td></tr><tr><td><strong>Connector</strong></td><td>Connectivity to any data source (e.g. SaaS, API, Internal Customer API, Database, File Store).</td></tr><tr><td><strong>Endpoint</strong></td><td>A specific instance of a Connector for the type of data you want to connect to (e.g. Salesforce Account Data).</td></tr><tr><td><strong>Endpoint Action</strong></td><td>A specific set of instructions on how the Endpoint performs tasks such as reading, writing, and deleting data.</td></tr><tr><td><strong>Publisher</strong></td><td>An Endpoint that triggers data to be integrated.</td></tr><tr><td><strong>Subscriber</strong></td><td>An Endpoint that receives data to be integrated.</td></tr><tr><td><strong>Data Hub</strong></td><td>A logical grouping of Endpoints that make up a single data synchronization solution.</td></tr><tr><td><strong>Agent</strong></td><td>At the center of all transactions, an Agent is constantly pushing data out and receiving data in.</td></tr></tbody></table><h2 id="conventions-used-in-this-guide" tabindex="-1">Conventions Used in This Guide <a class="header-anchor" href="#conventions-used-in-this-guide" aria-label="Permalink to &quot;Conventions Used in This Guide&quot;">​</a></h2><p>Throughout this guide, you will encounter the following callout types:</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>Useful information or a helpful tip regarding the current topic.</p></div><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Critical information regarding the current topic.</p></div><details class="details custom-block"><summary>Advanced Tool</summary><p>Descriptions of advanced features within the software, intended for those with developer knowledge and skills.</p></details><details class="details custom-block"><summary>Advanced Configuration</summary><p>Specific implementation examples of advanced features, intended to give developers a broader view of atypical applications.</p></details><div class="info custom-block"><p class="custom-block-title">Example</p><p>Analogies and/or examples for added illustration and understanding.</p></div><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>Recommendations on software setup and maintenance.</p></div><h2 id="ui-icon-reference" tabindex="-1">UI Icon Reference <a class="header-anchor" href="#ui-icon-reference" aria-label="Permalink to &quot;UI Icon Reference&quot;">​</a></h2><p>Throughout the application, icons appear on endpoint cards, action trees, and status indicators. Here is a reference for what each icon means.</p><h3 id="endpoint-card-icons" tabindex="-1">Endpoint Card Icons <a class="header-anchor" href="#endpoint-card-icons" aria-label="Permalink to &quot;Endpoint Card Icons&quot;">​</a></h3><div class="icon-legend"><table tabindex="0"><thead><tr><th style="text-align:center;">Icon</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:center;"><i class="fa-solid fa-clock text-secondary"></i></td><td><strong>Interval Scheduler</strong> — This endpoint runs on a timed interval</td></tr><tr><td style="text-align:center;"><i class="fa-solid fa-calendar text-secondary"></i></td><td><strong>Day of Week / Month Scheduler</strong> — This endpoint runs on a weekly or monthly schedule</td></tr><tr><td style="text-align:center;"><i class="fa-solid fa-play-pause text-secondary"></i></td><td><strong>On Demand</strong> — This endpoint can be triggered manually (click to run)</td></tr><tr><td style="text-align:center;"><i class="fa-solid fa-key text-warning"></i></td><td><strong>Key Replication</strong> — This endpoint has key replication actions configured</td></tr><tr><td style="text-align:center;"><i class="fa-solid fa-triangle-exclamation text-warning"></i></td><td><strong>Connector Not Found</strong> — The connector associated with this endpoint is missing</td></tr></tbody></table></div><h3 id="action-tree-icons" tabindex="-1">Action Tree Icons <a class="header-anchor" href="#action-tree-icons" aria-label="Permalink to &quot;Action Tree Icons&quot;">​</a></h3><div class="icon-legend"><table tabindex="0"><thead><tr><th style="text-align:center;">Icon</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td><strong>API Read Action</strong> — Reads data from an API endpoint</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-floppy-disk"></i></td><td><strong>API Save Action</strong> — Writes data to an API endpoint</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-trash-can"></i></td><td><strong>API Delete Action</strong> — Deletes data via an API endpoint</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-database"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td><strong>SQL Read Action</strong> — Reads data from a SQL database</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-database"></i> <i class="fa-regular fa-floppy-disk"></i></td><td><strong>SQL Save Action</strong> — Writes data to a SQL database</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-file"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td><strong>File Read Action</strong> — Reads data from a file source</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-file"></i> <i class="fa-regular fa-floppy-disk"></i></td><td><strong>File Save Action</strong> — Writes data to a file destination</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-hourglass-clock"></i></td><td><strong>Get Session Values</strong> — Extracts values from a prior API response for use in subsequent actions</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-key"></i> <i class="fa-regular fa-upload"></i></td><td><strong>Obtain Primary Key</strong> — Scrapes and indexes the primary key from a save response</td></tr></tbody></table></div><h3 id="status-indicators" tabindex="-1">Status Indicators <a class="header-anchor" href="#status-indicators" aria-label="Permalink to &quot;Status Indicators&quot;">​</a></h3><div class="icon-legend"><table tabindex="0"><thead><tr><th style="text-align:center;">Icon</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:center;"><i class="fa-solid fa-circle text-success"></i></td><td><strong>Record Exists</strong> — Entity found in the index</td></tr><tr><td style="text-align:center;"><i class="fa-solid fa-circle text-secondary"></i></td><td><strong>Record Not Found</strong> — Entity not in the index</td></tr><tr><td style="text-align:center;"><span class="badge bg-secondary">Draft</span></td><td><strong>Draft</strong> — Work-in-progress configuration version</td></tr><tr><td style="text-align:center;"><span class="badge bg-success">Live</span></td><td><strong>Live</strong> — Currently deployed production version</td></tr></tbody></table></div><h2 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h2><p>Upon logging into Central for the first time, you&#39;ll follow a six-step process to set up your integrations:</p><ol><li><strong><a href="./build-data-models.html">Build Data Models</a></strong> — Define Schemas (data values) and assign Schema Properties that describe the data you want to flow between systems.</li><li><strong><a href="./build-connectors.html">Configure Connectors</a></strong> — Identify and configure the applications and systems that store your Data Models, providing API credentials for each.</li><li><strong><a href="./build-datahubs.html">Build Data Hubs</a></strong> — Organize how data flows between systems by creating logical groupings of Endpoints, assigning publish/subscribe actions, and mapping data.</li><li><strong>Use <a href="./build-datahubs.html#add-endpoints-to-a-data-hub">Templates</a></strong> — Where available, leverage pre-configured Templates that tie specific Data Models to configured Endpoints with basic mapping already in place.</li><li><strong><a href="./deploy.html">Deploy</a></strong> — Push your configuration to a Live version. Data Hubs have internal versioning: Draft (work-in-progress), Live (production), and Previous Deploy (historical copies).</li><li><strong><a href="./monitor-dashboard.html">Monitor</a></strong> — Track integration health via the Dashboard, investigate individual messages and errors, and set up <a href="./monitor-alerts.html">Alerts</a> for error notifications.</li></ol><h3 id="organizing-your-data" tabindex="-1">Organizing Your Data <a class="header-anchor" href="#organizing-your-data" aria-label="Permalink to &quot;Organizing Your Data&quot;">​</a></h3><p>Before building, organize the data you&#39;d like to connect between systems:</p><ol><li>Document the data within each system that you want to connect</li><li>For each entity (e.g. Customer), list all fields you want to include (Name, Address, City, State, etc.)</li><li>Cross-reference corresponding fields across all systems you plan to connect</li><li>Any field you plan to read or write should be documented — each becomes a Schema Property</li></ol><div class="info custom-block"><p class="custom-block-title">Example</p><p>If your source of truth for Customer data is Salesforce, document all Customer fields you want to include (Name, Address, City, State, Zip Code, Phone Number, etc.). Then go to each connecting system and document the corresponding fields. You&#39;ll end up with a cross-reference of all Customer data across systems.</p></div><h3 id="build-data-models" tabindex="-1">Build Data Models <a class="header-anchor" href="#build-data-models" aria-label="Permalink to &quot;Build Data Models&quot;">​</a></h3><p>Data Models are customized, logical groups of data you are sharing between systems. Each Data Model is comprised of Schema Definitions — custom categories for the data you want to flow between systems (e.g. <em>Contact Person</em>).</p><p>Within a Schema Definition, you assign Schema Properties that detail the data for that definition. There are three types:</p><ul><li><strong>Simple Properties</strong> — Single value-to-value properties representing common, static data (e.g. customer name)</li><li><strong>Foreign Key Properties</strong> — Cross-referenced values that differ between systems (e.g. a customer record number in your sales system vs. your billing system)</li><li><strong>List Properties</strong> — Used for parent/child hierarchies (e.g. a sales order with header data and line items)</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Transaction Types tie directly to a Schema Definition and identify the actions to take on each data. See <a href="./build-data-models.html">Data Models</a> for details.</p></div><h3 id="configure-connectors" tabindex="-1">Configure Connectors <a class="header-anchor" href="#configure-connectors" aria-label="Permalink to &quot;Configure Connectors&quot;">​</a></h3><p>Connectors provide the security protocols to interact with specific software systems. When an Endpoint reads or writes data, it accesses the connecting system through an API. You&#39;ll provide the API credentials for each system that needs to connect to the Common Model.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Secure settings data can typically be found in the Admin settings of the connecting system. Links to common third-party authentication documentation can be found in the <a href="./reference-connectors.html">Connectors Catalog</a>.</p></div><h3 id="build-data-hubs" tabindex="-1">Build Data Hubs <a class="header-anchor" href="#build-data-hubs" aria-label="Permalink to &quot;Build Data Hubs&quot;">​</a></h3><p>A Data Hub is a logical grouping of Endpoints forming a single integration solution. Build Data Hubs like modules — cluster logical groupings to make them straightforward and easy to maintain. Each grouping is typically based on a specific entity (e.g. Customers) or a business process (e.g. Lead to Cash).</p><p>Endpoints can publish data to the hub, subscribe to data from the hub, or be bi-directional. Once all Endpoints are added, you map each Endpoint Action to tell the Common Model exactly how to perform tasks — what data to get, where to get it, where to publish it, and the method to read or write it.</p><div class="info custom-block"><p class="custom-block-title">Example</p><p>Salesforce references website data as <em>domain</em>; NetSuite references it as <em>url</em>. The Common Model lets you map both systems to a Schema Definition called <em>Website</em>. When subscribing from Salesforce, it reads the <em>domain</em> field; when publishing to NetSuite, it writes to the <em>url</em> field.</p></div><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>Create as few or as many Data Hubs as necessary. Fewer mappings per hub means easier maintenance. Each Data Hub has its own version control and can be updated independently. Start small and consolidate as needed.</p></div><h3 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h3><p>TeamCentral provides pre-configured Templates for common connectors. Templates tie specific Data Models to configured Endpoints and create basic mapping for you. When adding an Endpoint, select a Template if available, then choose which Schema Template and Transaction Type to apply.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Templates do not necessarily pre-build mapping for the entire connection. You may need to build additional mappings for unique Schema Definitions related to your business.</p></div><h3 id="deploy-and-monitor" tabindex="-1">Deploy and Monitor <a class="header-anchor" href="#deploy-and-monitor" aria-label="Permalink to &quot;Deploy and Monitor&quot;">​</a></h3><p>When your configuration is ready, deploy the Data Hub to push it to a Live version. Data Hubs have internal versioning:</p><ul><li><strong>Draft</strong> — A work-in-progress</li><li><strong>Live</strong> — A version running in production</li><li><strong>Previous Deploy</strong> — Previous Live copies</li></ul><p>Once deployed, monitor integration health through the <a href="./monitor-dashboard.html">Dashboard</a>, investigate individual <a href="./monitor-messages.html">Messages</a> and <a href="./monitor-error-logs.html">Error Logs</a>, manage the entity index, and configure <a href="./monitor-alerts.html">Alerts</a> for error notifications.</p>',55)])])}const p=e(i,[["render",s]]);export{g as __pageData,p as default};
